import streamlit as st
st.title("KUAN LOVE PUNA")
st.write("New Project")

name = st.text_input("Enter your name:")
if name:
    st.success(f"Hello {name}! 👋")

username = st.text_input("Enter your username")
email = st.text_input("Enter your email")
password = st.text_input("Enter your password", type = "password")

is_clicked = st.button("LOGIN")
if is_clicked:
   st.write(f"You're username is {username}")
   st.write(f"You're username is {email}")
   st.write(f"You're username is {password}")
   
if st.button("Show Image"):
    st.image("data:image/jpeg;base64,", caption="Sample Image")


with st.sidebar:
    st.header("SIRRRR TAPOS NA PO")